grid:


















































        select 'load$GridSalaryInformationPlanned$(this);' as message
return




        select 'dispose$GridSalaryInformationPlanned$(this);' as message
return







function load$GridSalaryInformationPlanned$(g) {g.add_commandEvent(on$GridSalaryInformationPlanned$ExecuteCommand);}
function dispose$GridSalaryInformationPlanned$(g) {try {g.remove_commandEvent(on$GridSalaryInformationPlanned$ExecuteCommand);} catch (ex) {}}
function on$GridSalaryInformationPlanned$ExecuteCommand(sender, e) {
  var action = e.type.Action, g = sender, f = g.get_element().parentForm;
	switch (action) {
    case 'AfterCloneRow':
      g.setItemFieldValue('stt_rec0', e.type.Value, '');
      break;
		case 'AfterInsertRow':
      if (g._rowCount == 1) {
				g._setItemValue(1, g._getColumnOrder('he_so_luong'), f.getItemValue('he_so_luong'));
				g._setItemValue(1, g._getColumnOrder('he_so_dc'), f.getItemValue('he_so_dc'));
				g._setItemValue(1, g._getColumnOrder('tien_khoan'), f.getItemValue('tien_khoan'));
			}
      break;
    default:
      break;
  }
}








